#!/usr/bin/env python3
"""Validate mesh-level Leech resident shell-cache benchmark certificates."""

from __future__ import annotations

import json
import sys
from pathlib import Path
from typing import Any


EXPECTED_VERSION = "gnosis.mesh-leech-shell-cache.v2"
EXPECTED_MODES = ["off", "sieve", "resident_cache"]


def fail(path: Path, message: str) -> None:
    raise SystemExit(f"{path}: {message}")


def obj(value: Any, name: str, path: Path) -> dict[str, Any]:
    if not isinstance(value, dict):
        fail(path, f"{name} must be an object")
    return value


def nonnegative_int(value: Any, name: str, path: Path) -> int:
    if not isinstance(value, int) or value < 0:
        fail(path, f"{name} must be a nonnegative integer")
    return value


def finite_number(value: Any, name: str, path: Path) -> float:
    if not isinstance(value, (int, float)) or value != value:
        fail(path, f"{name} must be a finite number")
    return float(value)


def validate(path: Path) -> None:
    payload = json.loads(path.read_text())
    root = obj(payload, "payload", path)

    if root.get("certificateVersion") != EXPECTED_VERSION:
        fail(path, f"certificateVersion must be {EXPECTED_VERSION!r}")
    if root.get("tool") != "bench-mesh-leech-toggle":
        fail(path, "tool must be 'bench-mesh-leech-toggle'")

    config = obj(root.get("config"), "config", path)
    width = nonnegative_int(config.get("width"), "config.width", path)
    height = nonnegative_int(config.get("height"), "config.height", path)
    stride = nonnegative_int(config.get("stride"), "config.stride", path)
    repeats = nonnegative_int(config.get("repeats"), "config.repeats", path)
    if width == 0 or height == 0 or stride == 0 or repeats == 0:
        fail(path, "width, height, stride, and repeats must be positive")

    modes = root.get("modes")
    if not isinstance(modes, list) or len(modes) != len(EXPECTED_MODES):
        fail(path, f"modes must contain {len(EXPECTED_MODES)} entries")
    by_name: dict[str, dict[str, Any]] = {}
    for mode in modes:
        mode_obj = obj(mode, "mode", path)
        name = mode_obj.get("name")
        if name not in EXPECTED_MODES:
            fail(path, f"unexpected mode name {name!r}")
        if name in by_name:
            fail(path, f"duplicate mode name {name!r}")
        by_name[name] = mode_obj
        finite_number(mode_obj.get("median_ms"), f"modes.{name}.median_ms", path)
        samples = mode_obj.get("samples_ms")
        if not isinstance(samples, list) or len(samples) != repeats:
            fail(path, f"modes.{name}.samples_ms must contain repeats samples")
        for i, sample in enumerate(samples):
            finite_number(sample, f"modes.{name}.samples_ms[{i}]", path)
        rgb_hash = mode_obj.get("rgb_hash")
        if not isinstance(rgb_hash, str) or len(rgb_hash) != 16:
            fail(path, f"modes.{name}.rgb_hash must be a 16-char hex string")
        int(rgb_hash, 16)

    if list(by_name.keys()) != EXPECTED_MODES:
        fail(path, f"modes must be ordered as {EXPECTED_MODES}")

    off_cert = obj(by_name["off"].get("certificate"), "off.certificate", path)
    sieve_cert = obj(by_name["sieve"].get("certificate"), "sieve.certificate", path)
    cache_cert = obj(by_name["resident_cache"].get("certificate"), "resident_cache.certificate", path)

    if off_cert.get("leech_visual_sieve") != "none":
        fail(path, "off mode must keep Leech visual sieve disabled")
    if sieve_cert.get("leech_visual_sieve") != "leech-shell":
        fail(path, "sieve mode must enable Leech visual sieve")
    if cache_cert.get("leech_visual_sieve") != "leech-shell":
        fail(path, "resident_cache mode must enable Leech visual sieve")

    sampled = nonnegative_int(cache_cert.get("sampled_pixels"), "resident_cache.sampled_pixels", path)
    if sampled == 0:
        fail(path, "resident_cache.sampled_pixels must be positive")
    addressable = nonnegative_int(
        cache_cert.get("addressable_shell_keys"),
        "resident_cache.addressable_shell_keys",
        path,
    )
    route_bucket_count = nonnegative_int(
        cache_cert.get("route_bucket_count"),
        "resident_cache.route_bucket_count",
        path,
    )
    route_hint_boost = finite_number(
        cache_cert.get("route_hint_boost"),
        "resident_cache.route_hint_boost",
        path,
    )
    unique_route_buckets = nonnegative_int(
        cache_cert.get("unique_route_buckets"),
        "resident_cache.unique_route_buckets",
        path,
    )
    hint_entries = nonnegative_int(
        cache_cert.get("route_bucket_hint_entries"),
        "resident_cache.route_bucket_hint_entries",
        path,
    )
    hint_reuses = nonnegative_int(
        cache_cert.get("route_bucket_hint_reuses"),
        "resident_cache.route_bucket_hint_reuses",
        path,
    )
    hint_applies = nonnegative_int(
        cache_cert.get("route_bucket_hint_applies"),
        "resident_cache.route_bucket_hint_applies",
        path,
    )
    hint_mean_delta = finite_number(
        cache_cert.get("route_bucket_hint_mean_gate_delta"),
        "resident_cache.route_bucket_hint_mean_gate_delta",
        path,
    )
    hint_max_delta = finite_number(
        cache_cert.get("route_bucket_hint_max_gate_delta"),
        "resident_cache.route_bucket_hint_max_gate_delta",
        path,
    )
    hint_mean_admission = finite_number(
        cache_cert.get("route_bucket_mean_admission"),
        "resident_cache.route_bucket_mean_admission",
        path,
    )
    hint_max_admission = finite_number(
        cache_cert.get("route_bucket_max_admission"),
        "resident_cache.route_bucket_max_admission",
        path,
    )
    stores = nonnegative_int(cache_cert.get("resident_cache_stores"), "resident_cache.stores", path)
    hits = nonnegative_int(cache_cert.get("resident_cache_hits"), "resident_cache.hits", path)
    payload_reuses = nonnegative_int(
        cache_cert.get("resident_cache_payload_reuses"),
        "resident_cache.payload_reuses",
        path,
    )
    bucket_reuses = nonnegative_int(
        cache_cert.get("resident_cache_bucket_reuses"),
        "resident_cache.bucket_reuses",
        path,
    )
    misses = nonnegative_int(cache_cert.get("resident_cache_misses"), "resident_cache.misses", path)
    entries = nonnegative_int(cache_cert.get("resident_cache_entries"), "resident_cache.entries", path)
    if cache_cert.get("resident_cache_enabled") is not True:
        fail(path, "resident_cache mode must report resident_cache_enabled=true")
    if addressable == 0 or stores == 0 or entries == 0:
        fail(path, "resident_cache mode must store at least one addressable shell route")
    if route_bucket_count == 0 or unique_route_buckets == 0:
        fail(path, "resident_cache mode must report route bucket occupancy")
    if not 0.0 < route_hint_boost <= 0.25:
        fail(path, "resident_cache route_hint_boost must be in (0, 0.25]")
    if hint_entries == 0:
        fail(path, "resident_cache mode must build route-bucket admission hints")
    if not 0.0 <= hint_mean_admission <= 1.0 or not 0.0 <= hint_max_admission <= 1.0:
        fail(path, "route-bucket admission hints must stay in [0, 1]")
    if hits == 0:
        fail(path, "resident_cache mode must report at least one exact-address hit")
    if payload_reuses == 0:
        fail(path, "resident_cache mode must reuse at least one resident route payload")
    if payload_reuses != hits:
        fail(path, "resident_cache payload_reuses must equal exact-address hits")
    if bucket_reuses == 0:
        fail(path, "resident_cache mode must reuse at least one resident route bucket")
    if bucket_reuses != payload_reuses:
        fail(path, "resident_cache bucket_reuses must equal payload_reuses")
    if hint_reuses == 0:
        fail(path, "resident_cache mode must reuse at least one admission hint")
    if hint_reuses != payload_reuses:
        fail(path, "route_bucket_hint_reuses must equal payload_reuses")
    if hint_applies == 0:
        fail(path, "resident_cache mode must apply at least one admission hint")
    if hint_applies != hint_reuses:
        fail(path, "route_bucket_hint_applies must equal hint_reuses")
    if hint_mean_delta < 0.0 or hint_max_delta < 0.0 or hint_max_delta < hint_mean_delta:
        fail(path, "route-bucket hint gate deltas must be ordered nonnegative values")
    if hint_max_delta == 0.0:
        fail(path, "resident_cache route-bucket hints must introduce a positive gate delta")

    invariants = obj(root.get("invariants"), "invariants", path)
    if invariants.get("sieve_matches_off_rgb") is not True:
        fail(path, "sieve telemetry must preserve baseline RGB")
    if invariants.get("cache_matches_sieve_rgb") is not False:
        fail(path, "cache hotpath must diverge from sieve RGB")
    if invariants.get("cache_matches_off_rgb") is not False:
        fail(path, "cache hotpath must diverge from baseline RGB")

    cache_admission = obj(root.get("cacheAdmission"), "cacheAdmission", path)
    if cache_admission.get("candidate") is not True:
        fail(path, "cacheAdmission.candidate must be true")

    print(
        f"{path}: ok modes=3 sampled={sampled} addressable={addressable} "
        f"hits={hits} payload_reuses={payload_reuses} "
        f"bucket_reuses={bucket_reuses} hint_reuses={hint_reuses} "
        f"hint_applies={hint_applies} "
        f"misses={misses} stores={stores}"
    )


def main(argv: list[str]) -> int:
    if len(argv) != 2:
        print("usage: validate-mesh-leech-shell-cache.py <certificate.json>", file=sys.stderr)
        return 2
    validate(Path(argv[1]))
    return 0


if __name__ == "__main__":
    raise SystemExit(main(sys.argv))
